package de.chrgroth.gradle.plugins.releasenotesimport org.gradle.api.Projectimport java.io.Filedata class ReleasenotesConfiguration(    val name: String,    val outputPath: String,    val snippetsPath: String,    val templatesPath: String,    val bugfixesHeader: String,    val bugfixesFooter: String,    val featuresHeader: String,    val featuresFooter: String,    val highlightsHeader: String,    val highlightsFooter: String,    val updateNoticesHeader: String,    val updateNoticesFooter: String,    val dateFormat: String,) {    fun init(dir: File): ReleaseNotesProcessor = ReleaseNotesProcessor(        name = name,        outputFile = dir.resolve(outputPath),        snippetsFolder = dir.resolve(snippetsPath),        templatesFolder = dir.resolve(templatesPath),        bugfixesHeader = bugfixesHeader,        bugfixesFooter = bugfixesFooter,        featuresHeader = featuresHeader,        featuresFooter = featuresFooter,        highlightsHeader = highlightsHeader,        highlightsFooter = highlightsFooter,        updateNoticesHeader = updateNoticesHeader,        updateNoticesFooter = updateNoticesFooter,        dateFormat = dateFormat,    )}open class ReleasenotesExtension(val project: Project) {    var mainBranch = "main"    var enforceOnNonMainBranch = true    val configurations: MutableList<ReleasenotesConfiguration> = mutableListOf(        ReleasenotesConfiguration(            name = "default",            outputPath = "RELEASENOTES.md",            snippetsPath = "snippets",            templatesPath = "templates",            bugfixesHeader = "## Bugfixes",            bugfixesFooter = "",            featuresHeader = "## New Features",            featuresFooter = "",            highlightsHeader = "## Highlights",            highlightsFooter = "",            updateNoticesHeader = "## Update Notices",            updateNoticesFooter = "",            dateFormat = "yyyy.MM.dd",        ),        ReleasenotesConfiguration(            name = "german",            outputPath = "RELEASENOTES_DE.md",            snippetsPath = "snippets-de",            templatesPath = "templates-de",            bugfixesHeader = "## Bugfixes",            bugfixesFooter = "",            featuresHeader = "## New Features",            featuresFooter = "",            highlightsHeader = "## Highlights",            highlightsFooter = "",            updateNoticesHeader = "## Update Notices",            updateNoticesFooter = "",            dateFormat = "dd.MM.yyyy",        ),    )}